#!/usr/bin/env node
/**
 * Capture Full-Page Screenshots
 *
 * Takes PNG screenshots of the HTML preview files generated by
 * generate-all-previews.js using headless Playwright/Chromium.
 *
 * Prerequisites:
 *   npm install playwright
 *   npx playwright install chromium
 *
 * Usage:
 *   node scripts/capture-screenshots.js [--output-dir <path>]
 */

const fs = require('fs');
const path = require('path');

const args = process.argv.slice(2);
const outputDir = args.includes('--output-dir')
    ? args[args.indexOf('--output-dir') + 1]
    : path.join(__dirname, '..', 'docs', 'images', 'screenshots');

const views = [
    { file: 'preview-details.html',    output: '03-details-panel.png',    title: 'Details View' },
    { file: 'preview-chart.html',      output: '04-chart-view.png',       title: 'Chart View' },
    { file: 'preview-usage.html',      output: '05-usage-analysis.png',   title: 'Usage Analysis' },
    { file: 'preview-diagnostics.html', output: '06-diagnostics-panel.png', title: 'Diagnostics' },
];

async function captureScreenshots() {
    let chromium;
    try {
        ({ chromium } = require('playwright'));
    } catch {
        console.error('❌ Playwright not found. Install it first:');
        console.error('   npm install playwright && npx playwright install chromium');
        process.exit(1);
    }

    // Verify all preview files exist before starting the browser
    console.log('📂 Checking for preview files...');
    for (const view of views) {
        const filePath = path.join(outputDir, view.file);
        if (!fs.existsSync(filePath)) {
            console.error(`❌ Missing: ${view.file}`);
            console.error('   Run: node scripts/generate-all-previews.js first');
            process.exit(1);
        }
        console.log(`   ✅ ${view.file}`);
    }

    fs.mkdirSync(outputDir, { recursive: true });

    console.log('\n📸 Capturing screenshots with Playwright...');
    console.log('='.repeat(60));

    const browser = await chromium.launch({ headless: true });
    const context = await browser.newContext({
        viewport: { width: 1280, height: 900 },
        deviceScaleFactor: 2,
    });
    const page = await context.newPage();

    for (const view of views) {
        // file:// URLs need forward slashes on all platforms
        const fileUrl = `file://${path.resolve(path.join(outputDir, view.file)).replace(/\\/g, '/')}`;
        console.log(`\n📷 ${view.title}`);
        await page.goto(fileUrl, { waitUntil: 'networkidle' });
        const outPath = path.join(outputDir, view.output);
        await page.screenshot({ path: outPath, fullPage: true });
        const { size } = fs.statSync(outPath);
        console.log(`   ✅ ${view.output} (${(size / 1024).toFixed(1)} KB)`);
    }

    await browser.close();

    console.log('\n' + '='.repeat(60));
    console.log('✅ All screenshots captured!\n');
    console.log(`Saved to: ${outputDir}`);
    views.forEach(v => console.log(`  • ${v.output}`));
}

captureScreenshots().catch(err => {
    console.error('❌ Error:', err.message);
    process.exit(1);
});
